const pn = libphonenumber.parsePhoneNumber(local('number'), local('country_code_iso'));

var is_valid_number = pn.isValid();

var number_e164;

if (pn.isValid()) {
  number_e164 = pn.number;
  country_code_iso = pn.country;
} else {
  number_e164 = local('number');
}
